import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

export default function AddAccessContent() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    login: '',
    name: '',
    ticket: '',
    platform: '',
    action: '',
    file: null,
  });

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: files ? files[0] : value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // TODO: Send `formData` to your Flask API
    console.log('Submitted:', formData);
    navigate('/access');
  };

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-800 mb-4">Add Access</h1>
      <form
        onSubmit={handleSubmit}
        className="bg-white shadow-md rounded-lg p-6 space-y-4 max-w-xl"
      >
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Login</label>
          <input
            type="text"
            name="login"
            value={formData.login}
            onChange={handleChange}
            className="border rounded px-3 py-2"
            required
          />
        </div>
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Name</label>
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            className="border rounded px-3 py-2"
            required
          />
        </div>
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Ticket</label>
          <input
            type="text"
            name="ticket"
            value={formData.ticket}
            onChange={handleChange}
            className="border rounded px-3 py-2"
            required
          />
        </div>
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Platform</label>
          <select
            name="platform"
            value={formData.platform}
            onChange={handleChange}
            className="border rounded px-3 py-2"
            required
          >
            <option value="">Select platform</option>
            <option value="RBS">RBS</option>
            <option value="VOCALCOM">VOCALCOM</option>
            <option value="Other">Other</option>
          </select>
        </div>
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Action</label>
          <select
            name="action"
            value={formData.action}
            onChange={handleChange}
            className="border rounded px-3 py-2"
            required
          >
            <option value="">Select action</option>
            <option value="create">Create</option>
            <option value="update">Update</option>
            <option value="suspend">Suspend</option>
            <option value="delete">Delete</option>
          </select>
        </div>
        <div className="flex flex-col">
          <label className="mb-1 font-medium">Upload File</label>
          <input
            type="file"
            name="file"
            onChange={handleChange}
            className="border rounded px-3 py-2"
            accept=".pdf,.docx,.png,.jpg"
          />
        </div>
        <div className="flex justify-end space-x-4 pt-4">
          <button
            type="button"
            onClick={() => navigate('/access')}
            className="px-4 py-2 rounded bg-gray-200 hover:bg-gray-300"
          >
            Cancel
          </button>
          <button
            type="submit"
            className="px-4 py-2 rounded bg-blue-800 text-white hover:bg-blue-700"
          >
            Submit
          </button>
        </div>
      </form>
    </div>
  );
}
